{"command": "# 深入查看Hexagon目录结构
Write-Host "=== C:\Hexagon ==="
Get-ChildItem -Path "C:\Hexagon" -Depth 1 -ErrorAction SilentlyContinue | Select-Object FullName

Write-Host "`n=== C:\Program Files\Hexagon ==="
Get-ChildItem -Path "C:\Program Files\Hexagon" -Depth 1 -ErrorAction SilentlyContinue | Select-Object FullName

# 搜索所有盘符下的PCDLRN.exe (限制深度以提高速度)
Write-Host "`n=== Searching for PCDLRN.exe across system ==="
$drives = Get-PSDrive -PSProvider FileSystem | Where-Object { $_.Root -match '^[A-Z]:\\' }
foreach ($drive in $drives) {
    $result = Get-ChildItem -Path $drive.Root -Filter "PCDLRN.exe" -Recurse -ErrorAction SilentlyContinue -Depth 4
    if ($result) {
        $result | Select-Object FullName
    }
}

# 同时搜索PC-DMIS相关的可执行文件
Write-Host "`n=== Searching for PC-DMIS* executables ==="
foreach ($drive in $drives) {
    $result = Get-ChildItem -Path $drive.Root -Filter "PC-DMIS*.exe" -Recurse -ErrorAction SilentlyContinue -Depth 4
    if ($result) {
        $result | Select-Object FullName
    }
}", "description": "深入搜索PC-DMIS安装目录和可执行文件", "timeout": 60000}

{"command": "# 检查PCDLRN COM组件是否注册
$com = Get-ItemProperty -Path "HKCR:\CLSID\*" -ErrorAction SilentlyContinue | Where-Object { $_.'(default)' -like '*PCDLRN*' -or $_.'(default)' -like '*PC-DMIS*' } 2>$null
if ($com) {
    Write-Host "COM组件已注册:"
    $com | Select-Object PSChildName, '(default)' | Format-List
} else {
    Write-Host "尝试查找ProgID..."
    # 通过ProgID查找
    $progid = Get-ItemProperty -Path "HKCR:\PCDLRN.Application\CLSID" -ErrorAction SilentlyContinue
    if ($progid) {
        Write-Host "PCDLRN.Application 已注册，CLSID: $($progid.'(default)')"
    } else {
        Write-Host "PCDLRN.Application 未在注册表中找到"
    }

    # 检查Pcdlrn.tlb
    Write-Host "`n检查类型库:"
    if (Test-Path "D:\PC-Dmis\Pcdlrn.tlb") {
        Write-Host "Pcdlrn.tlb 存在"
    }
}

# 也检查一下Python是否能连接到PC-DMIS
$pythonCheck = @"
import sys
try:
    import win32com.client
    pcdmis = win32com.client.Dispatch("PCDLRN.Application")
    print(f"PC-DMIS 连接成功!")
    print(f"版本: {pcdmis.Version}")
except Exception as e:
    print(f"连接失败: {e}")
"@
Write-Host "`n=== Python COM连接测试 ==="
python -c $pythonCheck 2>&1", "description": "检查PC-DMIS COM组件注册和Python连接", "timeout": 30000}

{"command": "# 检查64位COM注册 (PC-DMIS 2020 R1 64-bit)
Write-Host "=== 检查 64-bit COM 注册 ==="
$clsid64 = Get-ItemProperty -Path "HKLM:\SOFTWARE\Classes\CLSID\*" -ErrorAction SilentlyContinue | 
    Where-Object { $_.'(default)' -like '*PCDLRN*' } | Select-Object PSChildName, '(default)'
if ($clsid64) { 
    $clsid64 | Format-List
} else { 
    Write-Host "PCDLRN CLSID not found under Classes\CLSID" 
}

# 检查HKCR
Write-Host "`n=== 检查 HKCR ==="
$hkcr = Get-ChildItem "HKCR:\" -ErrorAction SilentlyContinue | Where-Object { $_.PSChildName -like '*PCDLRN*' }
if ($hkcr) { $hkcr | Format-List } else { Write-Host "No PCDLRN under HKCR" }

# 检查 INTEROP.PCDLRN.DLL
Write-Host "`n=== INTEROP.PCDLRN.DLL 注册信息 ==="
$interop = Get-ItemProperty -Path "HKLM:\SOFTWARE\Classes\*\CLSID" -ErrorAction SilentlyContinue | 
    Where-Object { $_ -match 'PCDLRN' } 2>$null
if (-not $interop) { Write-Host "No interop registration found" }

# 查看Interop文件信息
Write-Host "`n=== 检查 INTEROP.PCDLRN.DLL ==="
if (Test-Path "D:\PC-Dmis\INTEROP.PCDLRN.DLL") {
    $file = Get-Item "D:\PC-Dmis\INTEROP.PCDLRN.DLL"
    Write-Host "INTEROP.PCDLRN.DLL 存在: $($file.Length) bytes"
}

# 检查COM是否通过reg-free manifest注册
Write-Host "`n=== 检查 PCDLRN.EXE.CONFIG 中的COM信息 ==="
$config = Get-Content "D:\PC-Dmis\PCDLRN.EXE.CONFIG" -ErrorAction SilentlyContinue
if ($config) {
    $comRelated = $config | Select-String -Pattern "clsid|COM|PCDLRN"
    if ($comRelated) { $comRelated } else { Write-Host "未发现COM相关配置" }
}", "description": "检查PC-DMIS COM注册详细信息"}

